#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-28

# test-ultrareview.sh — smoke test for #1542 (CC 2.1.120 `claude ultrareview` subcommand)
#
# Verifies the workflow YAML and SKILL.md changes are structurally sound.
# Does NOT execute `claude ultrareview` itself (that needs CC 2.1.120+ and an
# API key — runs in CI via .github/workflows/ultrareview.yml).

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

PASS=0
FAIL=0

check() {
  local name="$1"; shift
  if "$@" >/dev/null 2>&1; then
    echo "  PASS $name"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name"
    FAIL=$((FAIL + 1))
  fi
}

echo "Ultra Review wiring smoke tests (#1542)"
echo

WF="$PROJECT_ROOT/.github/workflows/ultrareview.yml"

echo "[workflow YAML]"
check "ultrareview workflow file exists"        test -f "$WF"
check "workflow uses claude ultrareview"        grep -q "claude ultrareview" "$WF"
check "workflow requests --json output"         grep -q -- "--json" "$WF"
check "workflow gates on CC version"            grep -q "claude ultrareview --help" "$WF"
check "workflow has fallback when subcommand missing"  grep -q "skip=true" "$WF"
check "workflow uses sticky comment marker"     grep -q "ultrareview-comment-marker" "$WF"
check "workflow pins action SHAs (no @v tags)"  bash -c "! grep -E 'uses: [^@]+@v[0-9]' '$WF'"
check "workflow yaml parses (yq)"               bash -c "command -v yq >/dev/null && yq '.' '$WF' >/dev/null || python3 -c 'import yaml; yaml.safe_load(open(\"$WF\"))'"
echo

echo "[skill wiring]"
check "/ork:create-pr documents pre-flight"     grep -q "ultrareview" "$PROJECT_ROOT/src/skills/create-pr/SKILL.md"
check "/ork:review-pr defers ultra mode"        grep -q "claude ultrareview" "$PROJECT_ROOT/src/skills/review-pr/SKILL.md"
echo

echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"
echo

if [[ $FAIL -gt 0 ]]; then exit 1; fi
exit 0
